body {
  font-family: system-ui, sans-serif;
  padding: 24px;
  max-width: 420px;
  margin: auto;
}

#new-task { display: flex; gap: 8px; }
input { flex: 1; padding: 8px; border-radius: 6px; border: 1px solid #ccc; }
button { padding: 8px 12px; border-radius: 6px; border: 0; background: #2a9d8f; color: white; cursor: pointer; }
ul { list-style: none; padding: 0; }
li { display: flex; justify-content: space-between; align-items: center; padding: 8px; margin-top: 6px; background: #f1f3f5; border-radius: 6px; }
li button { background: #e76f51; }

